%  \end{enumerate}
% A vertex algebra $V_\bullet$ together with a conformal element $\omega$ is called a \textit{conformal vertex algebra} or \textit{vertex operator algebra}.

\begin{definition}[ConformalElement]
  \label{def:conformal-element}
  \lean{VirasoroSheaves.TODO.ConformalElement}
  \uses{def:vertex-algebra}
  \textit{Source: Bojko--Lim--Moreira, Section 3.2.}
  A \emph{conformal element} in a vertex algebra \(V_\bullet\) is a vector
  \(\omega \in V_4\) such that the Fourier modes \(L_n \coloneqq \omega_{(n+1)}\),
  defined by \(Y(\omega, z) = \sum_{n \in \mathbb{Z}} L_n z^{-n-2}\), satisfy:
  \begin{enumerate}
  \item the Virasoro bracket:
        \([L_n, L_m] = (n-m) L_{m+n} + \tfrac{n^3-n}{12} \delta_{n+m,0} \cdot C\)
        for some \emph{central charge} \(C \in \mathbb{C}\);
